previewCss:
.darma-loader-uiverse-rotating-3d-cube__spinner {
  width: 44px;
  height: 44px;
  animation: darma-loader-uiverse-rotating-3d-cube-spinner-y0fdc1 2s infinite ease;
  transform-style: preserve-3d;
}
.darma-loader-uiverse-rotating-3d-cube__spinner > div {
  background-color: color-mix(in srgb, var(--loader-color, #004dff) 20%, transparent);
  height: 100%;
  position: absolute;
  width: 100%;
  border: 2px solid var(--loader-color, #004dff);
}
.darma-loader-uiverse-rotating-3d-cube__spinner div:nth-of-type(1) { transform: translateZ(-22px) rotateY(180deg); }
.darma-loader-uiverse-rotating-3d-cube__spinner div:nth-of-type(2) { transform: rotateY(-270deg) translateX(50%); transform-origin: top right; }
.darma-loader-uiverse-rotating-3d-cube__spinner div:nth-of-type(3) { transform: rotateY(270deg) translateX(-50%); transform-origin: center left; }
.darma-loader-uiverse-rotating-3d-cube__spinner div:nth-of-type(4) { transform: rotateX(90deg) translateY(-50%); transform-origin: top center; }
.darma-loader-uiverse-rotating-3d-cube__spinner div:nth-of-type(5) { transform: rotateX(-90deg) translateY(50%); transform-origin: bottom center; }
.darma-loader-uiverse-rotating-3d-cube__spinner div:nth-of-type(6) { transform: translateZ(22px); }
@keyframes darma-loader-uiverse-rotating-3d-cube-spinner-y0fdc1 {
  0% { transform: rotate(45deg) rotateX(-25deg) rotateY(25deg); }
  50% { transform: rotate(45deg) rotateX(-385deg) rotateY(25deg); }
  100% { transform: rotate(45deg) rotateX(-385deg) rotateY(385deg); }
}

